import { Component, EventEmitter, Input, Output } from '@angular/core';
import { ResumeTemplate } from '../../../core/models/resume.model';

@Component({
  selector: 'app-template-preview-modal',
  templateUrl: './template-preview-modal.component.html'
})
export class TemplatePreviewModalComponent {
  @Input() template: ResumeTemplate | null = null;
  @Input() favorite = false;
  @Output() close = new EventEmitter<void>();
  @Output() toggleFavorite = new EventEmitter<void>();

  get tags(): string[] {
    if (!this.template) {
      return [];
    }
    try {
      const parsed = JSON.parse(this.template.tagsJson);
      return Array.isArray(parsed) ? parsed : [];
    } catch {
      return [];
    }
  }

  get supportedSections(): string[] {
    if (!this.template) {
      return [];
    }
    try {
      const parsed = JSON.parse(this.template.supportedSectionsJson);
      return Array.isArray(parsed) ? parsed.map((item) => String(item)) : [];
    } catch {
      return [];
    }
  }
}
<div *ngIf="template" class="shell-card p-6">
  <div class="flex items-start justify-between gap-4">
    <div>
      <p class="eyebrow">Template Preview</p>
      <h3 class="mt-2 text-3xl font-extrabold text-[#17172b]">{{ template.name }}</h3>
      <p class="mt-3 text-sm text-[#667085]">{{ template.category }} | {{ template.layoutType }} | {{ template.styleType }}</p>
    </div>
    <div class="flex items-center gap-3">
      <button
        type="button"
        class="flex h-10 w-10 items-center justify-center rounded-full border border-[#d7dcff] bg-white text-lg transition hover:border-[#5b5cf0] hover:text-[#5b5cf0]"
        [attr.aria-pressed]="favorite"
        (click)="toggleFavorite.emit()">
        {{ favorite ? '♥' : '♡' }}
      </button>
      <button *ngIf="close.observers.length > 0" class="btn-secondary px-4 py-2 text-sm" type="button" (click)="close.emit()">Close</button>
    </div>
  </div>

  <div class="mt-6 grid gap-6 lg:grid-cols-[0.54fr_0.46fr]">
    <div class="overflow-hidden rounded-[24px] bg-[#f8f9ff]">
      <img [src]="template.previewImageUrl" [alt]="template.name" class="w-full object-cover object-top">
    </div>
    <div class="space-y-4">
      <div class="soft-card p-5">
        <p class="text-sm font-bold text-[#17172b]">Best for</p>
        <p class="mt-2 text-sm leading-6 text-[#667085]">{{ template.roleType }} candidates at {{ template.experienceLevel }} level.</p>
      </div>
      <div class="soft-card p-5">
        <div class="flex flex-wrap gap-2">
          <span *ngIf="template.atsFriendly" class="rounded-full bg-[#ecfdf3] px-3 py-1.5 text-xs font-bold text-[#16a34a]">ATS Friendly</span>
          <span class="rounded-full px-3 py-1.5 text-xs font-bold"
                [ngClass]="template.premium ? 'bg-[#fff0f0] text-[#ef4444]' : 'bg-[#ecfdf3] text-[#16a34a]'">
            {{ template.premium ? 'Premium' : 'Free' }}
          </span>
          <span class="rounded-full bg-[#edf2ff] px-3 py-1.5 text-xs font-semibold text-[#5b5cf0]">ATS Score 92/100</span>
        </div>
        <div class="mt-4 space-y-3 text-sm text-[#667085]">
          <p><span class="font-semibold text-[#17172b]">Layout:</span> {{ template.layoutType }}</p>
          <p><span class="font-semibold text-[#17172b]">Category:</span> {{ template.category }}</p>
        </div>
      </div>
      <div class="soft-card p-5">
        <p class="text-sm font-bold text-[#17172b]">Included sections</p>
        <div class="mt-3 flex flex-wrap gap-2">
          <span *ngFor="let section of supportedSections" class="rounded-full bg-[#f8f9ff] px-3 py-1.5 text-xs font-semibold text-[#475467]">
            {{ section | titlecase }}
          </span>
        </div>
      </div>
      <div class="soft-card p-5">
        <p class="text-sm font-bold text-[#17172b]">Tags</p>
        <div class="mt-3 flex flex-wrap gap-2">
          <span *ngFor="let tag of tags" class="rounded-full bg-[#edf2ff] px-3 py-1.5 text-xs font-semibold text-[#5b5cf0]">{{ tag }}</span>
        </div>
      </div>
    </div>
  </div>
</div>
